#!/usr/bin/env python3
import os
import sys
import subprocess

def main():
    repo_path = sys.argv[1] if len(sys.argv) > 1 else "."
    os.chdir(repo_path)

    # 1. Compile the generator natively
    subprocess.run([
        "clang", "-O2",
        "-o", "gen_parser",
        "src/parse/properties/css_property_parser_gen.c"
    ], check=True)

    # 2. Read properties.gen and generate each parser
    with open("src/parse/properties/properties.gen", "r") as f:
        for line in f:
            line = line.strip()
            if not line or line.startswith("#"):
                continue
            
            # Extract name before first colon
            name = line.split(":")[0].strip()
            
            # Execute the generator
            subprocess.run([
                "./gen_parser",
                "-o", f"src/parse/properties/autogenerated_{name}.c",
                line
            ], check=True)
            
    print("Successfully autogenerated all LibCSS property parser source files!")

if __name__ == "__main__":
    main()
